INSERT INTO `ai_messages` (`message_id`, `conversation_id`, `role`, `content`, `venue_ids`, `created_at`) VALUES
(1, 1, 'assistant', '👋 Hello! I\'m your AI event planning assistant powered by Google Gemini (Gemini Pro). I\'m here to help you find the perfect venue for your event!\n\nI can recommend venues based on:\n• Event type (Wedding, Corporate, Birthday, Concert, etc.)\n• Number of guests\n• Budget\n• Location preferences\n• Specific amenities you need\n\nTell me about your event, and I\'ll suggest the best venues from our database! What kind of event are you planning?', NULL, '2025-11-29 12:00:33'),
(2, 1, 'user', 'I want to have 18th birthday with 300 guests. I want it to take place in Batangas City. My budget for the event is 60,000.', NULL, '2025-11-29 12:00:42'),
(3, 1, 'assistant', 'Of course! An 18th birthday is a huge celebration, and I\'d be happy to help you find the perfect venue in Batangas City for 300 guests with a ₱60,000 budget.\n\nBased on your requirements, finding a venue for 300 guests within that budget is a bit tight, but definitely achievable, especially if your event is on a weekday. Here are the top 3 venues in Batangas City that match your needs:\n\n### Top Recommendations for Your 18th Birthday\n\n**1. La Solana Splendido Event Center**\nThis is an excellent choice as its pricing fits perfectly within your budget, even for a peak day, and it can comfortably accommodate all your guests with room to spare. Its versatile nature means you can decorate it to match any theme you have in mind for your debut.\n\n*   **Why it\'s a great match:** Its price range of ₱40,000 to ₱60,000 aligns perfectly with your budget. The capacity of 400 guests ensures a comfortable space for your 300 attendees.\n*   **Capacity:** 400 guests\n*   **Location:** Batangas City, Batangas\n*   **Pricing:** Weekday: ₱40,000 | Weekend: ₱55,000 | Peak: ₱60,000\n*   **Consideration:** The amenities are not listed, so you may want to inquire what\'s included in the rental fee (e.g., tables, chairs, basic sound system).\n\n**2. Shepherd\'s Events Garden**\nThis venue is another strong contender, offering a lovely garden-style setting that could be beautiful for an 18th birthday party. The capacity is a perfect match for your guest list, and the pricing is very close to your budget.\n\n*   **Why it\'s a great match:** It\'s designed for exactly 300 guests and its garden ambiance provides a beautiful backdrop for photos. A weekend event would be right at your budget limit.\n*   **Capacity:** 300 guests\n*   **Location:** Batangas City, Batangas\n*   **Pricing:** Weekday: ₱48,000 | Weekend: ₱60,000 | Peak: ₱65,000\n*   **Consideration:** A peak season booking would be slightly over budget at ₱65,000. It\'s best to confirm what\'s included in the package.\n\n**3. South Peak Garden & Events Place**\nThis venue also fits your location and capacity needs well. While the price isn\'t listed in our system, it\'s definitely worth contacting them. They might have special packages for debuts that could fit your budget.\n\n*   **Why it\'s a great match:** It\'s located in Batangas City and can hold up to 350 guests, making it suitable for your event size.\n*   **Capacity:** 350 guests\n*   **Location:** Batangas City, Batangas\n*   **Pricing:** Not listed (requires inquiry).\n*   **Consideration:** You will need to contact the venue directly for a price quote and to see if they can accommodate your ₱60,000 budget.\n\nI would recommend starting with **La Solana Splendido Event Center** as it most closely matches all your requirements.\n\nLet me know if you\'d like more details on any of these, or if you\'d like to adjust your search!', '[4,1,5]', '2025-11-29 12:01:05'),
(4, 3, 'assistant', '👋 Hello! I\'m your AI event planning assistant powered by Google Gemini (Gemini Pro). I\'m here to help you find the perfect venue for your event!\n\nI can recommend venues based on:\n• Event type (Wedding, Corporate, Birthday, Concert, etc.)\n• Number of guests\n• Budget\n• Location preferences\n• Specific amenities you need\n\nTell me about your event, and I\'ll suggest the best venues from our database! What kind of event are you planning?', NULL, '2025-11-30 15:17:59'),
(5, 3, 'user', 'Birthday party for 80 guests', NULL, '2025-11-30 15:18:02'),
(6, 3, 'assistant', 'Great! A birthday party for 80 guests sounds like a lot of fun. To help me find the perfect spot for your celebration, could you tell me a bit more about what you have in mind?\n\n*   **What\'s your preferred location?** (e.g., Tagaytay, Laguna, Batangas, etc.)\n*   **What kind of vibe are you going for?** (e.g., a rustic garden setting, a modern hall, something romantic?)\n*   **Do you have a budget in mind for the venue rental?**\n\nOnce I have these details, I can suggest some fantastic options that will make the birthday celebration truly special', NULL, '2025-11-30 15:18:17'),
(7, 3, 'user', 'I want a venue from China', NULL, '2025-11-30 15:21:08'),
(8, 3, 'assistant', 'Thank you for letting me know. I\'ve checked my database, and it seems all of our partner venues are currently located in the Philippines, specifically in the provinces of Cavite, Laguna, Batangas, and Quezon. I don\'t have any listings for venues in China at the moment.\n\nWould you be open to considering a venue in one of these beautiful Philippine locations for the birthday party? If so, I\'d be happy to help you find a great spot', NULL, '2025-11-30 15:21:19'),
(9, 4, 'assistant', '👋 Hello! I\'m your AI event planning assistant powered by Google Gemini (Gemini Pro). I\'m here to help you find the perfect venue for your event!\n\nI can recommend venues based on:\n• Event type (Wedding, Corporate, Birthday, Concert, etc.)\n• Number of guests\n• Budget\n• Location preferences\n• Specific amenities you need\n\nTell me about your event, and I\'ll suggest the best venues from our database! What kind of event are you planning?', NULL, '2025-11-30 16:33:10'),
(10, 5, 'assistant', '👋 Hello! I\'m your AI event planning assistant powered by Google Gemini (Gemini Pro). I\'m here to help you find the perfect venue for your event!\n\nI can recommend venues based on:\n• Event type (Wedding, Corporate, Birthday, Concert, etc.)\n• Number of guests\n• Budget\n• Location preferences\n• Specific amenities you need\n\nTell me about your event, and I\'ll suggest the best venues from our database! What kind of event are you planning?', NULL, '2025-12-01 06:51:11'),
(11, 5, 'user', 'Hello!', NULL, '2025-12-01 06:51:16'),
(12, 5, 'assistant', 'Hello there! I\'m excited to help you find the perfect venue.\n\nTo get started, could you tell me a little more about the event you have in mind? For example:\n\n*   **What type of event are you planning?** (e.g., a wedding, a corporate conference, a birthday party?)\n*   **How many guests are you expecting?**\n*   **Do you have a preferred location?** (e.g., Cavite, Laguna, Batangas?)', NULL, '2025-12-01 06:51:35');
