INSERT INTO `venues` (`venue_id`, `manager_id`, `location_id`, `venue_name`, `capacity`, `description`, `suitable_themes`, `venue_type`, `ambiance`, `availability_status`, `image`, `status`, `created_at`) VALUES
(7, 2, 10, 'Caleruega Church', 150, 'A stunning hilltop chapel and event venue overlooking Taal Lake. Features Mediterranean-inspired architecture, beautiful gardens, and breathtaking views. Ideal for weddings, christenings, and religious ceremonies.', 'Wedding, Christening, Anniversary, Engagement', 'Chapel & Garden', 'Elegant', 'available', , 'active', '2025-11-29 10:34:50');
